import sys

def is_extended_abc(s):
    if len(s) == 0:
        return True
    if s[0] != 'A':
        return False
    a_count = 0
    while a_count < len(s) and s[a_count] == 'A':
        a_count += 1
    if a_count == len(s):
        return True
    if s[a_count] != 'B':
        return False
    b_count = a_count
    while b_count < len(s) and s[b_count] == 'B':
        b_count += 1
    if b_count == len(s):
        return True
    if s[b_count] != 'C':
        return False
    c_count = b_count
    while c_count < len(s) and s[c_count] == 'C':
        c_count += 1
    return c_count == len(s)

def main():
    s = sys.stdin.readline().strip()
    if is_extended_abc(s):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    main()
